ALTER TABLE castle_edits ADD COLUMN IF NOT EXISTS status TEXT NOT NULL DEFAULT 'pending' CHECK (status IN ('pending', 'processing', 'done', 'error'));
ALTER TABLE castle_edits ADD COLUMN IF NOT EXISTS error_msg TEXT;
ALTER TABLE castle_edits ALTER COLUMN image_data_url DROP NOT NULL;
ALTER TABLE castle_edits ALTER COLUMN image_data_url SET DEFAULT NULL;

DO $$ BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_policies WHERE tablename = 'castle_edits' AND policyname = 'Public delete castle_edits'
  ) THEN
    CREATE POLICY "Public delete castle_edits" ON castle_edits FOR DELETE USING (true);
  END IF;
END $$;
